// Build list of [post_type, target_lang] pairs to process
const languages = $input.all().map(i => i.json);
const config = $('Config Variables').first().json;

const postTypes = ['post', 'page', 'product']; // ← ADD YOUR CPTs HERE
const defaultLang = languages.find(l => l.default)?.slug || 'en';
const targetLangs = languages.filter(l => !l.default).map(l => l.slug);

const jobs = [];
for (const pt of postTypes) {
  for (const lang of targetLangs) {
    jobs.push({
      post_type: pt,
      target_lang: lang,
      default_lang: defaultLang,
      wp_base_url: config.wp_base_url,
      deepseek_api_url: config.deepseek_api_url,
      deepseek_model: config.deepseek_model,
      posts_per_batch: config.posts_per_batch || 20,
      current_page: 1,
      has_more: true
    });
  }
}

return jobs.map(j => ({ json: j }));

// Flatten the response: one item per (post, target_lang) pair
const responses = $input.all();
const job = $('Build Post Type + Lang Jobs').first().json;
const allJobs = [];

for (const item of responses) {
  const response = item.json;
  if (!response.posts || response.posts.length === 0) continue;

  for (const post of response.posts) {
    for (const lang of post.missing_langs) {
      allJobs.push({
        json: {
          post_id: post.id,
          post_type: post.post_type,
          source_lang: post.source_lang,
          target_lang: lang,
          wp_base_url: job.wp_base_url,
          deepseek_api_url: job.deepseek_api_url,
          deepseek_model: job.deepseek_model
        }
      });
    }
  }
}
return allJobs;

const responses = $input.all();
const jobs = $('Flatten Post List').all();

return responses.map((inputItem, index) => {
  const payload = inputItem.json;
  const job = jobs[index].json;

  const bundle = {
    title:   payload.translatable.title,
    content: payload.translatable.content,
    excerpt: payload.translatable.excerpt,
    slug:    payload.translatable.slug,
  };

  const meta_to_translate = {};
  for (const [key, info] of Object.entries(payload.meta || {})) {
    if (info.translatable) {
      const val = (info.type === 'json' || info.type === 'serialized')
        ? JSON.stringify(info.raw_value)
        : String(info.raw_value);
      if (val && val.trim()) meta_to_translate[key] = val;
    }
  }

  const acf_to_translate = {};
  for (const [key, info] of Object.entries(payload.acf_fields || {})) {
    if (info.translatable && info.value) {
      acf_to_translate[key] = String(info.value);
    }
  }

  const taxonomy_source_terms = {};
  for (const [tax, terms] of Object.entries(payload.taxonomies || {})) {
    taxonomy_source_terms[tax] = terms.map(t => ({
      source_term_id: t.term_id,
      translations: t.translations
    }));
  }

  // ── Block segments: pass the FULL original text (with HTML) to DeepSeek.
  // DeepSeek is instructed to preserve tags and only translate text nodes.
  // On return, we do a direct string replace in the raw post_content.
  const has_blocks = payload.has_blocks === true;
  const block_segments = [];

  if (has_blocks && payload.blocks?.segments?.length > 0) {
    for (const seg of payload.blocks.segments) {
      if (seg.text && seg.text.trim()) {
        block_segments.push({
          index:    seg.index,
          sub_path: seg.sub_path,
          is_html:  seg.is_html,
          original: seg.text,   // exact string that exists in post_content
        });
      }
    }
  }

  return {
    json: {
      ...job,
      post_payload: payload,
      bundle,
      meta_to_translate,
      acf_to_translate,
      taxonomy_source_terms,
      has_blocks,
      block_segments,
      block_original_content: has_blocks ? (payload.blocks?.original_content ?? null) : null,
      target_lang: job.target_lang,
      source_lang: payload.source_lang,
    }
  };
});

return $input.all().map(inputItem => {
  const item = inputItem.json;
  const target_lang = item.target_lang;
  const source_lang = item.source_lang;

  // ── Helper: decode JSON unicode escapes (\u003c → <) so DeepSeek sees clean HTML ──
  function decodeUnicodeEscapes(str) {
    if (typeof str !== 'string') return str;
    return str.replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) =>
      String.fromCharCode(parseInt(hex, 16))
    );
  }

  const system_prompt = `You are a professional multilingual content translator for a WordPress website.
You will receive a JSON object with text fields to translate from ${source_lang} to ${target_lang}.
Rules:
1. Translate EVERY field value accurately and naturally.
2. For HTML strings: preserve ALL HTML tags exactly as-is — only translate the visible text between the tags.
3. For the 'slug' field: output a URL-friendly lowercase string (hyphens, no spaces, no special chars).
4. Return ONLY valid JSON. No markdown fences, no explanations, no extra keys.
5. Keep every JSON key exactly as given.
6. For the "blocks" array: each item has an "index" and "original". Return the same array with a "translated" key containing the fully translated string (HTML tags preserved). Never omit any block item.`;

  // Build the blocks array — decode unicode escapes so DeepSeek receives real HTML, not \u003c etc.
  const blocks_for_ds = (item.block_segments || []).map(seg => ({
    index:    seg.index,
    sub_path: seg.sub_path,
    original: decodeUnicodeEscapes(seg.original),
  }));

  const payload_to_translate = {
    core:   item.bundle,
    meta:   item.meta_to_translate,
    acf:    item.acf_to_translate,
    blocks: blocks_for_ds,
  };

  const user_prompt = `Translate from ${source_lang} to ${target_lang}. Return ONLY the JSON:\n${JSON.stringify(payload_to_translate, null, 2)}`;

  return {
    json: {
      ...item,
      deepseek_request: {
        model:       item.deepseek_model,
        max_tokens:  8192,
        temperature: 0.2,
        messages: [
          { role: 'system', content: system_prompt },
          { role: 'user',   content: user_prompt },
        ]
      }
    }
  };
});

const responses = $input.all();
const reqItems = $('Prepare DeepSeek Request').all();

// ── Helper: decode JSON unicode escapes (\u003c → <) ──
function decodeUnicodeEscapes(str) {
  if (typeof str !== 'string') return str;
  return str.replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) =>
    String.fromCharCode(parseInt(hex, 16))
  );
}

return responses.map((inputItem, index) => {
  const deepseek_resp = inputItem.json;
  const item = reqItems[index].json;

  if (!deepseek_resp.choices || deepseek_resp.choices.length === 0) {
    throw new Error('DeepSeek returned no choices for post ' + item.post_payload.id);
  }

  let raw_content = deepseek_resp.choices[0].message.content.trim();
  raw_content = raw_content.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');

  let translated;
  try {
    translated = JSON.parse(raw_content);
  } catch(e) {
    throw new Error('Failed to parse DeepSeek JSON for post ' + item.post_payload.id + ': ' + e.message);
  }

  // ── Resolve taxonomy term IDs in target language ──
  const tax_map = {};
  for (const [tax, source_terms] of Object.entries(item.taxonomy_source_terms || {})) {
    const target_ids = [];
    for (const t of source_terms) {
      const translated_term_id = t.translations[item.target_lang];
      if (translated_term_id) target_ids.push(translated_term_id);
    }
    if (target_ids.length > 0) tax_map[tax] = target_ids;
  }

  // ── Rebuild post_content by direct string replacement ──
  // Both the original segment text AND the translated text are decoded from unicode escapes
  // so that the replacement correctly matches what exists in the raw post_content.
  let final_content = null;

  if (item.has_blocks && item.block_original_content && translated.blocks?.length > 0) {
    let content = item.block_original_content;

    for (const tb of translated.blocks) {
      const orig_seg = (item.block_segments || []).find(s => s.index === tb.index);
      if (!orig_seg) continue;

      // Decode both sides so we're comparing/replacing clean HTML, not \u003c escape sequences
      const original_text   = decodeUnicodeEscapes(orig_seg.original);
      const translated_text = decodeUnicodeEscapes(tb.translated);

      if (!original_text || !translated_text) continue;
      if (original_text === translated_text) continue;

      // Also replace the unicode-escaped version of the original in post_content
      // (post_content may still hold \u003c form — replace both variants)
      content = content.split(orig_seg.original).join(translated_text);
      if (orig_seg.original !== original_text) {
        content = content.split(original_text).join(translated_text);
      }
    }

    final_content = content;
  }

  return {
    json: {
      wp_base_url: item.wp_base_url,
      save_payload: {
        source_id:   item.post_payload.id,
        target_lang: item.target_lang,
        translated: {
          title:   translated.core?.title   || item.bundle.title,
          content: item.has_blocks ? null : (translated.core?.content || item.bundle.content),
          excerpt: translated.core?.excerpt || item.bundle.excerpt,
          slug:    translated.core?.slug    || (item.bundle.slug + '-' + item.target_lang),
        },
        meta:          translated.meta || {},
        acf:           translated.acf  || {},
        tax_map:       tax_map,
        block_content: final_content,
      }
    }
  };
});

const responses = $input.all();
for (const resp of responses) {
  const result = resp.json;
  console.log(`✅ POST saved: ID=${result.post_id}, lang=${result.target_lang}, action=${result.action}`);
}
return responses;

// Build [taxonomy, target_lang] pairs for term translation
// ← ADD / EDIT your taxonomy slugs here:
const taxonomies = ['category', 'product_cat', 'product_tag', 'pa_color'];

const config = $('Term Config Variables').first().json;

// Pull languages dynamically from GET Languages (Terms)
const languages = $('GET Languages (Terms)').all().map(i => i.json);
const defaultLang = languages.find(l => l.default)?.slug || 'en';
const targetLangs = languages.filter(l => !l.default).map(l => l.slug);

const jobs = [];
for (const tax of taxonomies) {
  for (const lang of targetLangs) {
    jobs.push({
      taxonomy: tax,
      target_lang: lang,
      default_lang: defaultLang,
      wp_base_url: config.wp_base_url,
      deepseek_api_url: config.deepseek_api_url,
      deepseek_model: config.deepseek_model,
    });
  }
}

return jobs.map(j => ({ json: j }));

const responses = $input.all();
const jobItems = $('Build Taxonomy + Lang Jobs').all();
const allJobs = [];

for (let i = 0; i < responses.length; i++) {
  const response = responses[i].json;
  // Index-match each response to its originating job so config is never mismatched
  const job = (jobItems[i] || jobItems[0]).json;

  if (!response.terms || response.terms.length === 0) continue;

  for (const term of response.terms) {
    for (const lang of term.missing_langs) {
      allJobs.push({
        json: {
          term_id:      term.term_id,
          taxonomy:     term.taxonomy,
          source_lang:  term.source_lang,
          target_lang:  lang,
          wp_base_url:      job.wp_base_url,
          deepseek_api_url: job.deepseek_api_url,
          deepseek_model:   job.deepseek_model,
        }
      });
    }
  }
}
return allJobs;

return $input.all().map(inputItem => {
  const d = inputItem.json;  // fully merged item from Merge Term Payload

  const system_prompt = `You are a professional multilingual WordPress taxonomy translator.
Translate the provided JSON from ${d.source_lang} to ${d.target_lang}.
Rules:
1. Translate name and description naturally.
2. For 'slug': produce a URL-friendly lowercase hyphenated version.
3. Translate all meta text values.
4. Return ONLY the translated JSON — no markdown, no explanation.`;

  const to_translate = { core: d.term_payload.translatable, meta: {} };

  for (const [key, info] of Object.entries(d.term_payload.meta || {})) {
    if (info.translatable && info.raw_value) {
      to_translate.meta[key] = String(info.raw_value);
    }
  }

  return {
    json: {
      // Carry all job context forward so Merge DS Term Response can re-attach it
      term_id:         d.term_id,
      taxonomy:        d.taxonomy,
      source_lang:     d.source_lang,
      target_lang:     d.target_lang,
      wp_base_url:     d.wp_base_url,
      deepseek_api_url: d.deepseek_api_url,
      deepseek_model:  d.deepseek_model,
      term_payload:    d.term_payload,
      deepseek_request: {
        model:       d.deepseek_model,
        max_tokens:  2048,
        temperature: 0.2,
        messages: [
          { role: 'system', content: system_prompt },
          { role: 'user',   content: `Translate this JSON from ${d.source_lang} to ${d.target_lang}:\n${JSON.stringify(to_translate, null, 2)}` }
        ]
      }
    }
  };
});

return $input.all().map((inputItem, index) => {
  const d = inputItem.json;  // merged item: DeepSeek response + job context

  if (!d.choices || d.choices.length === 0) {
    throw new Error(`DeepSeek returned no choices for term_id=${d.term_id} lang=${d.target_lang}`);
  }

  let raw = d.choices[0].message.content.trim();
  raw = raw.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');

  let translated;
  try {
    translated = JSON.parse(raw);
  } catch(e) {
    throw new Error(`Failed to parse DeepSeek JSON for term_id=${d.term_id} lang=${d.target_lang}: ${e.message}`);
  }

  return {
    json: {
      wp_base_url: d.wp_base_url,
      save_payload: {
        source_id:   d.term_id,
        taxonomy:    d.taxonomy,
        target_lang: d.target_lang,
        translated: {
          name:        translated.core?.name        || d.fallback_name,
          description: translated.core?.description || d.fallback_description,
          slug:        translated.core?.slug        || (d.fallback_slug + '-' + d.target_lang),
        },
        meta: translated.meta || {}
      }
    }
  };
});

const responses = $input.all();
for (const resp of responses) {
  const result = resp.json;
  console.log(`✅ TERM saved: ID=${result.term_id}, lang=${result.target_lang}, action=${result.action}`);
}
return responses;

// Merge the GET Term Payload HTTP response with job context from Flatten Term List.
// HTTP nodes replace the item entirely, so we re-attach job fields here by index.
const payloads  = $input.all();
const jobItems  = $('Flatten Term List').all();

return payloads.map((inputItem, index) => {
  const payload = inputItem.json;          // raw HTTP response from GET Term Payload
  const job     = jobItems[index].json;    // matching job from Flatten Term List

  return {
    json: {
      term_payload:      payload,           // full payload from PHP endpoint
      term_id:           job.term_id,
      taxonomy:          job.taxonomy,
      source_lang:       job.source_lang,
      target_lang:       job.target_lang,
      wp_base_url:       job.wp_base_url,
      deepseek_api_url:  job.deepseek_api_url,
      deepseek_model:    job.deepseek_model,
    }
  };
});

// Merge the DeepSeek HTTP response with job context from Prepare Term DeepSeek Request.
// HTTP nodes replace the item entirely, so we re-attach job fields here by index.
const dsResponses = $input.all();
const reqItems    = $('Prepare Term DeepSeek Request').all();

return dsResponses.map((inputItem, index) => {
  const ds_resp = inputItem.json;        // raw DeepSeek API response
  const req     = reqItems[index].json;  // matching prepared request item

  return {
    json: {
      // DeepSeek response fields
      choices:         ds_resp.choices,
      // Job context carried forward
      term_id:         req.term_id,
      taxonomy:        req.taxonomy,
      source_lang:     req.source_lang,
      target_lang:     req.target_lang,
      wp_base_url:     req.wp_base_url,
      deepseek_model:  req.deepseek_model,
      // Fallback values in case translation fails
      fallback_name:        req.term_payload?.translatable?.name        || '',
      fallback_description: req.term_payload?.translatable?.description || '',
      fallback_slug:        req.term_payload?.translatable?.slug        || '',
    }
  };
});
